import { Component } from '@angular/core';
import { Store } from '../models/store.model';
import { IProduct, ICategory } from '../models/product.model';
import { CategoryNamePipe } from '../category-name-pipe';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-products',
  imports: [CommonModule, FormsModule, CategoryNamePipe],
  templateUrl: './products.component.html',
  styleUrls: ['./products.component.css']
})
export class ProductsComponent {

  // Task 2a - Store object and StoreOwner
  store: Store = new Store(
    'TechMart',
    ['Cairo Branch', 'Alex Branch', 'Giza Branch'],
  );

  storeOwner: string = 'Shahd ElMeniawy';

  // Task 4a - Product list using IProduct
  productList: IProduct[] = [
    { ID: 1, Name: 'Laptop Pro', Quantity: 5, Price: 25000, Img: 'https://img.freepik.com/free-photo/laptop-with-sun-background_1232-429.jpg', CategoryID: 1 },
    { ID: 2, Name: 'Gaming Mouse', Quantity: 1, Price: 850, Img: 'data:image/jpeg;base64,', CategoryID: 2 },
    { ID: 3, Name: 'Mechanical Keyboard', Quantity: 2, Price: 1200, Img: 'data:image/jpeg;base64,', CategoryID: 2 },
    { ID: 4, Name: 'USB-C Hub', Quantity: 0, Price: 450, Img: 'data:image/jpeg;base64,', CategoryID: 3 },
    { ID: 5, Name: '4K Monitor', Quantity: 3, Price: 12000, Img: 'data:image/jpeg;base64,', CategoryID: 1 },
    { ID: 6, Name: 'Webcam HD', Quantity: 0, Price: 1500, Img: 'data:image/jpeg;base64,', CategoryID: 3 },
  ];

  categories: ICategory[] = [
    { ID: 1, Name: 'Computers' },
    { ID: 2, Name: 'Peripherals' },
    { ID: 3, Name: 'Accessories' },
  ];

  // Task 6 - Search by name (two-way binding)
  searchText: string = '';

  // Bonus - Selected category (two-way binding)
  selectedCategoryID: number = 0;

  // Filtered products getter
  get filteredProducts(): IProduct[] {
    return this.productList.filter(p => {
      const matchesName = p.Name.toLowerCase().includes(this.searchText.toLowerCase());
      const matchesCategory = this.selectedCategoryID === 0 || p.CategoryID === +this.selectedCategoryID;
      return matchesName && matchesCategory;
    });
  }

  // Task 5b - Switch on quantity status
  getQuantityStatus(quantity: number): string {
    switch (true) {
      case quantity === 0:
        return 'Out of Stock';
      case quantity === 1:
        return 'Last One Item!';
      case quantity === 2:
        return 'Last Two Items!';
      default:
        return 'In Stock';
    }
  }

  getStatusClass(quantity: number): string {
    switch (true) {
      case quantity === 0: return 'status-out';
      case quantity <= 2: return 'status-low';
      default: return 'status-in';
    }
  }

  // Task 5c - Buy button decreases quantity
  buy(product: IProduct): void {
    if (product.Quantity > 0) {
      product.Quantity--;
    }
  }

  // Task 5d - Details button shows alert
  showDetails(product: IProduct): void {
    const category = this.categories.find(c => c.ID === product.CategoryID)?.Name || 'Unknown';
    alert(
      `Product Details\n` +
      `──────────────────\n` +
      `ID       : ${product.ID}\n` +
      `Name     : ${product.Name}\n` +
      `Price    : ${product.Price} EGP\n` +
      `Quantity : ${product.Quantity}\n` +
      `Category : ${category}`
    );
  }
}